package com.evolua.chat.application; import com.evolua.chat.domain.Message; import com.evolua.chat.domain.MessageRepository; import java.time.Instant; import java.util.List; import org.springframework.stereotype.Service; @Service public class MessageService { private final MessageRepository repository; public MessageService(MessageRepository repository) { this.repository = repository; } public Message create(String userId, String recipientId, String content) { return repository.save(new Message(null, userId, recipientId, content, Instant.now())); } public List<Message> list(String userId) { return repository.findAllByUserId(userId); } }
